package kotlinx.coroutines.flow

import kotlinx.coroutines.CoroutineStart
import kotlinx.coroutines.launch
import kotlinx.coroutines.yield
import kotlin.test.Test
import kotlin.test.assertContentEquals

class SharedFlowToListDestinationTest : TestBase() {
    @Test
    fun testSharedFlowToListFillsProvidedDestinationOnCancellation() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(acc)
        }

        sharedFlow.emit(1)
        sharedFlow.emit(2)
        yield()

        job.cancel()
        job.join()

        assertContentEquals(listOf(1, 2), acc)
    }

    @Test
    fun testSharedFlowToSetFillsProvidedDestinationOnCancellation() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = linkedSetOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toSet(acc)
        }

        sharedFlow.emit(1)
        sharedFlow.emit(2)
        yield()

        job.cancel()
        job.join()

        assertContentEquals(listOf(1, 2), acc.toList())
    }
}
"}

